import{_ as o,o as a,c as d,ag as l}from"./chunks/framework.DAAaZ98D.js";const m=JSON.parse('{"title":"仓库与发布流程","description":"","frontmatter":{},"headers":[],"relativePath":"docs/repo-workflow.md","filePath":"docs/repo-workflow.md"}'),i={name:"docs/repo-workflow.md"};function t(c,e,r,n,s,h){return a(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="仓库与发布流程" tabindex="-1">仓库与发布流程 <a class="header-anchor" href="#仓库与发布流程" aria-label="Permalink to &quot;仓库与发布流程&quot;">​</a></h1><p>这篇页面用最简单的话说明这个仓库是怎么工作的。</p><h2 id="两个部分" tabindex="-1">两个部分 <a class="header-anchor" href="#两个部分" aria-label="Permalink to &quot;两个部分&quot;">​</a></h2><ul><li><code>main</code> 是源码分支</li><li><code>gh-pages</code> 是已发布的网站分支</li></ul><p>你平时要改的是 <code>main</code> 里的 Markdown 文件，不是 <code>gh-pages</code> 里的 HTML 文件。</p><h2 id="网站是怎么生成的" tabindex="-1">网站是怎么生成的 <a class="header-anchor" href="#网站是怎么生成的" aria-label="Permalink to &quot;网站是怎么生成的&quot;">​</a></h2><ol><li>你编辑 <code>main/content/</code> 里的 <code>.md</code> 文件，然后提交</li><li>仓库把 Markdown 处理成网页内容</li><li>构建后生成静态 HTML 和资源文件</li><li>部署到 <code>gh-pages</code></li></ol><p>所以，Markdown 是“源文件”，<code>gh-pages</code> 是“网站成品”。</p><h2 id="你应该改哪里" tabindex="-1">你应该改哪里 <a class="header-anchor" href="#你应该改哪里" aria-label="Permalink to &quot;你应该改哪里&quot;">​</a></h2><ul><li>网站首页：<code>content/index.md</code></li><li>说明文档：<code>content/docs/*.md</code></li><li>新帖子：<code>content/post/&lt;帖子名&gt;/index.md</code></li><li>帖子图片：放在同一个帖子文件夹里</li></ul><p>如果你要更新一篇帖子，就直接修改那篇帖子的 <code>.md</code> 文件。</p><h2 id="怎么上传帖子" tabindex="-1">怎么上传帖子 <a class="header-anchor" href="#怎么上传帖子" aria-label="Permalink to &quot;怎么上传帖子&quot;">​</a></h2><p>如果你想新增或更新投稿，通常这样做。克隆repo到本地后(在 <code>main</code> 分支)：</p><ol><li>创建帖子目录，比如 <code>content/post/&lt;帖子名&gt;/</code></li><li>编辑里面的 <code>index.md</code></li><li>保存图片或附件到同一目录</li><li>提交 <code>main</code> 分支的PR</li></ol><h2 id="如何更改网页主题色" tabindex="-1">如何更改网页主题色 <a class="header-anchor" href="#如何更改网页主题色" aria-label="Permalink to &quot;如何更改网页主题色&quot;">​</a></h2><p>在 <code>src/.vitepress/theme/style.css</code> 中进行颜色设置</p><h2 id="如何更改右上角链接" tabindex="-1">如何更改右上角链接 <a class="header-anchor" href="#如何更改右上角链接" aria-label="Permalink to &quot;如何更改右上角链接&quot;">​</a></h2><p>在 <code>src/.vitepress/config.ts</code> 中进行设置</p>',18)])])}const u=o(i,[["render",t]]);export{m as __pageData,u as default};
